import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Routes, Route, Navigate, useLocation } from 'react-router-dom';
import HomePage from './components/HomePage';
import MainLayout from './components/layout/MainLayout';
import DashboardList from './components/dashboard/DashboardList';
import MetricsDashboard from './components/dashboard/MetricsDashboard';
import DataSourcesPage from './components/pages/DataSourcesPage';
import AlertsPage from './components/pages/AlertsPage';
import SettingsPage from './components/pages/SettingsPage';
import './App.css';

/** Maps a pathname to its Prometheus source key (or null for pages that need no fetch). */
function getSourceForPath(pathname) {
  if (pathname === '/' || pathname === '/home' || pathname.startsWith('/dashboards/explorer')) {
    return 'default';
  }
  if (pathname.startsWith('/dashboards/proxmox')) return 'proxmox-prom';
  if (pathname.startsWith('/dashboards/vcenter')) return 'vcenter-prom';
  if (pathname.startsWith('/dashboards/nebula')) return 'nebulanew-prom';
  return null;
}

/** Pure helper — pick a sensible default metric for a given source. */
function getDefaultMetric(metrics, source) {
  if (!metrics || metrics.length === 0) return null;
  switch (source) {
    case 'proxmox-prom':
      return (
        metrics.find(m => m.name.toLowerCase().includes('pve')) ||
        metrics.find(m => m.name.toLowerCase().includes('cpu')) ||
        metrics[0]
      );
    case 'nebulanew-prom':
      return (
        metrics.find(m => m.name.toLowerCase().includes('kube')) ||
        metrics.find(m => m.name.toLowerCase().includes('pod')) ||
        metrics[0]
      );
    case 'vcenter-prom':
      return (
        metrics.find(m => m.name.toLowerCase().includes('vm')) ||
        metrics.find(m => m.name.toLowerCase().includes('cpu')) ||
        metrics[0]
      );
    default:
      return metrics[0];
  }
}

function AppRoutes() {
  const location = useLocation();
  const [selectedMetric, setSelectedMetric] = useState(null);
  const [metrics, setMetrics] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const lastSourceRef = useRef(undefined);
  const refreshControllerRef = useRef(null);

  /**
   * Fetches metric names + metadata for a given source.
   * Pass an AbortSignal to cancel if the user navigates away mid-flight.
   * Pass silent=true for background refreshes so the UI is not cleared.
   */
  const fetchMetrics = useCallback(async (source, signal, silent = false) => {
    try {
      setError(null);
      if (!silent) setLoading(true);

      const srcParam = source ? `?source=${encodeURIComponent(source)}` : '';

      // Fetch labels and metadata in parallel
      const [labelsRes, metadataRes] = await Promise.all([
        fetch(`/api/v1/label/__name__/values${srcParam}`, { signal }),
        fetch(`/api/v1/metadata${srcParam}`, { signal }),
      ]);

      const [labelsData, metadataData] = await Promise.all([
        labelsRes.json(),
        metadataRes.json(),
      ]);

      if (labelsData.status === 'success' && Array.isArray(labelsData.data)) {
        const parsedMetrics = labelsData.data.map((name) => {
          const entry = metadataData.data?.[name]?.[0];
          return {
            name,
            description: entry?.help || 'No description available',
            type: entry?.type || 'unknown',
            help: entry?.help || 'No description available',
          };
        });

        setMetrics(parsedMetrics);
        setSelectedMetric(getDefaultMetric(parsedMetrics, source));
        setError(null);
      } else {
        setError('Failed to parse metrics data');
      }
    } catch (err) {
      if (err.name === 'AbortError') return; // Navigation cancelled this fetch — ignore
      setError('Failed to fetch metrics: ' + err.message);
    } finally {
      if (!silent) setLoading(false);
    }
  }, []);

  /** Triggered on every pathname change. Cancels any in-flight fetch for the previous source. */
  useEffect(() => {
    const key = getSourceForPath(location.pathname);

    if (key === null) {
      // Pages that don't need metrics (e.g. /alerts, /settings)
      setLoading(false);
      return;
    }

    const source = key === 'default' ? undefined : key;
    lastSourceRef.current = source;

    // Immediately clear stale metrics from the previous source
    setMetrics([]);
    setSelectedMetric(null);
    setError(null);

    const controller = new AbortController();
    fetchMetrics(source, controller.signal);

    // Cleanup: abort the fetch if the user navigates again before it finishes
    return () => controller.abort();
  }, [location.pathname, fetchMetrics]);

  /** Manual refresh — silently re-fetches without clearing the current display. */
  const refresh = useCallback(() => {
    if (refreshControllerRef.current) {
      refreshControllerRef.current.abort();
    }
    refreshControllerRef.current = new AbortController();
    fetchMetrics(lastSourceRef.current, refreshControllerRef.current.signal, true);
  }, [fetchMetrics]);

  const handleMetricSelect = useCallback((metric) => {
    setSelectedMetric(metric);
  }, []);

  if (loading && metrics.length === 0) {
    return (
      <div className="loading">
        <img src="/opsight-logo.svg" alt="OpSight Logo" className="loading-logo animate-spin" />
        <span className="ml-2">Loading OpSight metrics...</span>
      </div>
    );
  }

  if (error && metrics.length === 0) {
    return (
      <div className="error">
        <h2>Error</h2>
        <p>{error}</p>
        <button
          className="btn btn-primary mt-4"
          type="button"
          onClick={() => fetchMetrics(lastSourceRef.current, new AbortController().signal)}
        >
          Retry
        </button>
      </div>
    );
  }

  return (
    <MainLayout onRefresh={refresh}>
      <Routes>
        <Route path="/" element={<Navigate to="/home" replace />} />
        <Route path="/home" element={<HomePage metrics={metrics} />} />
        <Route path="/dashboards" element={<DashboardList />} />
        <Route
          path="/dashboards/explorer"
          element={
            <MetricsDashboard
              metrics={metrics}
              selectedMetric={selectedMetric}
              onMetricSelect={handleMetricSelect}
            />
          }
        />
        <Route
          path="/dashboards/proxmox"
          element={
            <MetricsDashboard
              metrics={metrics}
              selectedMetric={selectedMetric}
              onMetricSelect={handleMetricSelect}
              source="proxmox-prom"
            />
          }
        />
        <Route
          path="/dashboards/vcenter"
          element={
            <MetricsDashboard
              metrics={metrics}
              selectedMetric={selectedMetric}
              onMetricSelect={handleMetricSelect}
              source="vcenter-prom"
            />
          }
        />
        <Route
          path="/dashboards/nebula"
          element={
            <MetricsDashboard
              metrics={metrics}
              selectedMetric={selectedMetric}
              onMetricSelect={handleMetricSelect}
              source="nebulanew-prom"
            />
          }
        />
        <Route path="/alerts" element={<AlertsPage />} />
        <Route path="/data-sources" element={<DataSourcesPage />} />
        <Route path="/settings" element={<SettingsPage />} />
        <Route path="*" element={<Navigate to="/home" replace />} />
      </Routes>
    </MainLayout>
  );
}

export default function App() {
  return <AppRoutes />;
}
